final:
module gray_code_counter_4bit (
    input wire clk,
    input wire rst,
    output reg [3:0] gray
    );

reg [3:0] obf_binary_count;

always @(posedge clk) begin
    if (rst) begin
        obf_binary_count <= 4'b0000;
    end else begin
        obf_binary_count <= obf_binary_count + 1;
    end
end

always @(*) begin
    gray = (obf_binary_count >> 1) ^ obf_binary_count;
end

endmodule
